from __future__ import annotations

import asyncio
from collections.abc import Awaitable, Callable


async def run_tasks(tasks: list[Callable[[], Awaitable[None]]], max_concurrent: int) -> None:
    """Run async zero-argument callables with a concurrency cap.

    If cancellation begins, no new queued tasks are started. Tasks already
    started are awaited with cancellation suppressed so their cleanup code can
    finish running.
    """

    if max_concurrent <= 0:
        raise ValueError("max_concurrent must be > 0")

    started: set[asyncio.Task[None]] = set()
    iterator = iter(tasks)
    cancellation_started = False

    async def start_next() -> bool:
        try:
            coro = next(iterator)()
        except StopIteration:
            return False
        task = asyncio.create_task(coro)
        started.add(task)
        task.add_done_callback(started.discard)
        return True

    try:
        for _ in range(max_concurrent):
            if not await start_next():
                break

        while started:
            done, _ = await asyncio.wait(started, return_when=asyncio.FIRST_COMPLETED)
            for task in done:
                task.result()
                if not cancellation_started:
                    await start_next()
    except asyncio.CancelledError:
        cancellation_started = True
        for task in list(started):
            task.cancel()
        if started:
            await asyncio.gather(*started, return_exceptions=True)
        raise
    except KeyboardInterrupt:
        cancellation_started = True
        for task in list(started):
            task.cancel()
        if started:
            await asyncio.gather(*started, return_exceptions=True)
        raise

